code = """import json

# Load the 35 paper titles from 2016 physical activity domain
paper_path = locals().get('var_functions.query_db:2')
with open(paper_path, 'r') as f:
    papers = json.load(f)

titles_2016_pa = []
for paper in papers:
    filename = paper.get('filename', '')
    title = filename.replace('.txt', '') if filename else ''
    text = paper.get('text', '')
    if '2016' in text and 'physical activity' in text.lower() and title:
        titles_2016_pa.append(title)

# Load activity-related papers from citations  
citation_path = locals().get('var_functions.query_db:48')
with open(citation_path, 'r') as f:
    activity_citations = json.load(f)

# Match papers between both lists
paper_dict = {title: 0 for title in titles_2016_pa}

for item in activity_citations:
    title = item.get('title', '')
    total = int(item.get('total', 0))
    if title in paper_dict:
        paper_dict[title] = total

# Create sorted results
results = []
for title, citations in paper_dict.items():
    if citations > 0:  # Only include papers with citations
        results.append({'title': title, 'total_citations': citations})

results.sort(key=lambda x: x['total_citations'], reverse=True)

print('Papers with citations found:', len(results))
print('\nTop papers:')
for i, paper in enumerate(results, 1):
    print(str(i) + '. ' + paper['title'])
    print('   Total citations: ' + str(paper['total_citations']))

output = {'papers': results, 'total_with_citations': len(results), 'total_papers': len(titles_2016_pa)}
print('__RESULT__:')
print(json.dumps(output))"""

